'use strict'

/**
 * Checks, if two reasons are similar
 */
function isReasonSimilar (reason1, reason2) {
  let sameAmountOfReasons = Array.isArray(reason1) && Array.isArray(reason2) && reason1.length === reason2.length
  let isSimilar = sameAmountOfReasons
  if (sameAmountOfReasons) {
    for (let index in reason1) {
      message1 = reason1[index].message
      message2 = reason2[index].message
      isSimilar = message1 === message2
      if (!isSimilar) break;
    }
  }
  return isSimilar
}

/**
 * Checks, if two values are similar
 */
function isValueSimilar (value1, value2) {
  let isSimilar = value1 === value2
  return isSimilar
}

/**
 * Checks, if two entries are similar. They are similar, if the reasons are similar and the values are
 * identical
 */
function isEntrySimilar(entry1, entry2) {
  let entriesAreValid = entry1 !== undefined && entry1 !== null & entry2 !== undefined && entry2 !== null
  let reasonsAreSimilar = entriesAreValid && isReasonSimilar(entry1.reasion, entry2.reason)
  let valuesAreSimilar = entriesAreValid && isValueSimilar(entry1.value, entry2.value)
  return reasonsAreSimilar && valuesAreSimilar  
}

